parameters.text:
=You are an email triage assistant for a B2B operations consulting firm. Analyze the email and return ONLY a valid JSON object with these exact fields: {"category": "new_inquiry|client_support|billing|escalation", "priority": "critical|high|medium|low", "summary": "max 15 words describing the request", "route_to": "sales|account_manager|admin"}. Return no other text.

---

From: {{ $json.from.name }} <{{ $json.from.value[0].address }}>
Subject: {{ $json.subject }}
Body:
{{ $json.text }}

parameters.jsCode:
const raw = $input.first().json.text || $input.first().json.output || '';
const original = $('Gmail Trigger').item.json;

let parsed;
try {
  const cleaned = raw.replace(/^```(?:json)?\n?/i, '').replace(/```$/, '').trim();
  parsed = JSON.parse(cleaned);
} catch (err) {
  return [{ json: { parse_error: true, raw_response: raw, error: 'parse error' } }];
}

const validCategories = ['new_inquiry', 'client_support', 'billing', 'escalation'];
const validPriorities = ['critical', 'high', 'medium', 'low'];
const validRoutes = ['sales', 'account_manager', 'admin'];

if (!validCategories.includes(parsed.category) ||
    !validPriorities.includes(parsed.priority) ||
    !validRoutes.includes(parsed.route_to)) {
  return [{ json: { parse_error: true, raw_response: raw, error: 'Invalid field values in AI response.' } }];
}

const fromRaw = original.From || original.from || '';
const emailMatch = fromRaw.match(/<(.+?)>/);
const nameMatch = fromRaw.match(/^(.+?)\s*</);
const senderEmail = emailMatch ? emailMatch[1] : fromRaw.trim();
const senderName = nameMatch ? nameMatch[1].trim() : senderEmail;
const nameParts = senderName.split(' ');

return [{
  json: {
    sender_email: senderEmail,
    sender_name: senderName,
    sender_first_name: nameParts[0] || '',
    sender_last_name: nameParts.slice(1).join(' ') || '',
    subject: original.Subject || original.subject || '',
    original_body: original.snippet || original.text || original.body || '',
    timestamp: new Date().toISOString(),
    category: parsed.category,
    priority: parsed.priority,
    summary: parsed.summary,
    route_to: parsed.route_to,
    parse_error: false
  }
}];

